CREATE TABLE employees (
  id INT PRIMARY KEY,
  name VARCHAR(100),
  department VARCHAR(50),
  salary DECIMAL(10,2)
);

CREATE TABLE users (
  user_id INT PRIMARY KEY,
  email VARCHAR(255) UNIQUE,
  name VARCHAR(100)
);

CREATE TABLE orders (
  order_id INT PRIMARY KEY,
  customer_id INT,
  amount DECIMAL(10,2),
  FOREIGN KEY (customer_id) REFERENCES customers(customer_id)
);

DELETE FROM employees WHERE department = 'HR';
TRUNCATE TABLE temp_logs;
DROP TABLE old_records;

SELECT * FROM employees WHERE phone IS NULL;
SELECT * FROM employees WHERE phone IS NOT NULL;

-- This will NOT work as expected:
-- SELECT * FROM employees WHERE phone = NULL;

-- Create
INSERT INTO employees (name, salary) VALUES ('Manav', 75000);

-- Read
SELECT * FROM employees;

-- Update
UPDATE employees SET salary = 80000 WHERE name = 'Manav';

-- Delete
DELETE FROM employees WHERE name = 'Manav';

UPDATE employees
SET salary = salary * 1.10
WHERE department = 'Engineering';

-- DISTINCT: unique departments
SELECT DISTINCT department FROM employees;

-- GROUP BY: count per department
SELECT department, COUNT(*) AS headcount
FROM employees
GROUP BY department;

SELECT name, salary FROM employees
ORDER BY salary DESC;

SELECT * FROM products
ORDER BY category ASC, price DESC;

-- Names starting with 'A'
SELECT * FROM employees WHERE name LIKE 'A%';

-- Names ending with 'kumar'
SELECT * FROM employees WHERE name LIKE '%kumar';

-- Exactly 5-letter names
SELECT * FROM employees WHERE name LIKE '_____';

-- Instead of:
SELECT * FROM employees WHERE dept = 'HR' OR dept = 'IT' OR dept = 'Finance';

-- Use IN:
SELECT * FROM employees WHERE dept IN ('HR', 'IT', 'Finance');

SELECT COUNT(*) AS total_employees FROM employees;
SELECT AVG(salary) AS avg_salary FROM employees;
SELECT MAX(salary) AS highest_salary FROM employees;
SELECT SUM(amount) AS total_sales FROM orders;

SELECT department, COUNT(*) AS headcount, AVG(salary) AS avg_salary
FROM employees
GROUP BY department;

-- Counts all rows (including NULLs)
SELECT COUNT(*) FROM employees;

-- Counts only rows where phone is not NULL
SELECT COUNT(phone) FROM employees;

CREATE TABLE users (
  id INT PRIMARY KEY,
  email VARCHAR(255) UNIQUE,
  phone VARCHAR(15) UNIQUE
);

CREATE TABLE orders (
  id INT PRIMARY KEY,
  status VARCHAR(20) DEFAULT 'pending',
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE employees (
  id INT PRIMARY KEY,
  age INT CHECK (age >= 18 AND age <= 65),
  salary DECIMAL(10,2) CHECK (salary > 0)
);

SELECT e.name, d.department_name
FROM employees e
JOIN departments d ON e.department_id = d.id;

SELECT o.order_id, c.name
FROM orders o
INNER JOIN customers c ON o.customer_id = c.id;

SELECT e.name, d.department_name
FROM employees e
LEFT JOIN departments d ON e.department_id = d.id;

SELECT e.name, d.department_name
FROM employees e
RIGHT JOIN departments d ON e.department_id = d.id;

SELECT e.name, d.department_name
FROM employees e
FULL OUTER JOIN departments d ON e.department_id = d.id;

SELECT color.name, size.label
FROM colors color
CROSS JOIN sizes size;

SELECT e.name AS employee, m.name AS manager
FROM employees e
LEFT JOIN employees m ON e.manager_id = m.id;

SELECT name, salary
FROM employees
WHERE salary > (SELECT AVG(salary) FROM employees);

-- IN
SELECT * FROM customers
WHERE id IN (SELECT customer_id FROM orders);

-- EXISTS
SELECT * FROM customers c
WHERE EXISTS (SELECT 1 FROM orders o WHERE o.customer_id = c.id);

CREATE INDEX idx_dept_salary
ON employees(department, salary);

-- ✅ Uses index (left-most prefix)
SELECT * FROM employees WHERE department = 'IT';

-- ✅ Uses index (both columns)
SELECT * FROM employees WHERE department = 'IT' AND salary > 50000;

-- ❌ May not use index efficiently
SELECT * FROM employees WHERE salary > 50000;

-- ❌ Bad index: low cardinality
CREATE INDEX idx_gender ON employees(gender);

-- ✅ Good index: high cardinality, frequently searched
CREATE INDEX idx_email ON employees(email);

SELECT name FROM employees
UNION
SELECT name FROM contractors;

-- Removes duplicates
SELECT city FROM customers UNION SELECT city FROM suppliers;

-- Keeps all rows
SELECT city FROM customers UNION ALL SELECT city FROM suppliers;

-- GROUP BY: 1 row per department
SELECT department, AVG(salary) FROM employees GROUP BY department;

-- Window: all rows preserved + department avg
SELECT name, department, salary,
  AVG(salary) OVER (PARTITION BY department) AS dept_avg
FROM employees;

SELECT name, department, salary,
  RANK() OVER (PARTITION BY department ORDER BY salary DESC) AS dept_rank
FROM employees;

BEGIN TRANSACTION;

UPDATE accounts SET balance = balance - 5000 WHERE id = 1;
UPDATE accounts SET balance = balance + 5000 WHERE id = 2;

COMMIT;
-- If any step fails: ROLLBACK;

BEGIN;
DELETE FROM orders WHERE status = 'cancelled';
-- Oops, wrong condition!
ROLLBACK;  -- Nothing was deleted

BEGIN;
DELETE FROM orders WHERE status = 'cancelled' AND year = 2022;
COMMIT;  -- Changes saved permanently

BEGIN;
INSERT INTO orders VALUES (1, 'Laptop', 75000);
SAVEPOINT sp1;
INSERT INTO orders VALUES (2, 'Mouse', 500);
-- Undo only the mouse insert
ROLLBACK TO sp1;
COMMIT; -- Only laptop order is saved

CREATE PROCEDURE get_employees_by_dept(
  IN dept_name VARCHAR(50)
)
BEGIN
  SELECT * FROM employees WHERE department = dept_name;
END;

-- Call it
CALL get_employees_by_dept('Engineering');

-- Function: returns a value, usable in SELECT
CREATE FUNCTION get_tax(price DECIMAL)
RETURNS DECIMAL
BEGIN
  RETURN price * 0.18;
END;

SELECT name, price, get_tax(price) AS tax FROM products;

-- Procedure: performs actions
CALL update_employee_status(101, 'inactive');

CREATE TRIGGER log_salary_change
AFTER UPDATE ON employees
FOR EACH ROW
BEGIN
  IF OLD.salary <> NEW.salary THEN
    INSERT INTO salary_audit (emp_id, old_salary, new_salary, changed_at)
    VALUES (NEW.id, OLD.salary, NEW.salary, NOW());
  END IF;
END;

-- CTE: readable, reusable
WITH dept_stats AS (
  SELECT department, AVG(salary) AS avg_sal FROM employees GROUP BY department
)
SELECT * FROM dept_stats WHERE avg_sal > 70000;

-- Subquery: inline
SELECT * FROM (
  SELECT department, AVG(salary) AS avg_sal FROM employees GROUP BY department
) t WHERE avg_sal > 70000;

EXPLAIN SELECT * FROM employees WHERE department = 'Engineering';

EXPLAIN ANALYZE
SELECT e.name, d.name
FROM employees e
JOIN departments d ON e.dept_id = d.id
WHERE e.salary > 50000;

-- Full scan (no index on department)
SELECT * FROM employees WHERE department = 'HR';

-- Index scan (index exists on department)
CREATE INDEX idx_dept ON employees(department);
SELECT * FROM employees WHERE department = 'HR';

-- ❌ Function on column: index ignored
SELECT * FROM employees WHERE UPPER(name) = 'MANAV';

-- ❌ Leading wildcard: index ignored
SELECT * FROM employees WHERE name LIKE '%kumar';

-- ✅ Trailing wildcard: index used
SELECT * FROM employees WHERE name LIKE 'Man%';

-- ❌ Selecting all columns
SELECT * FROM orders;

-- ✅ Select only needed columns
SELECT order_id, amount, status FROM orders;

-- ❌ Correlated subquery (runs per row)
SELECT name FROM employees e
WHERE salary > (SELECT AVG(salary) FROM employees WHERE dept_id = e.dept_id);

-- ✅ Rewritten with JOIN
SELECT e.name
FROM employees e
JOIN (SELECT dept_id, AVG(salary) AS avg_sal FROM employees GROUP BY dept_id) d
  ON e.dept_id = d.dept_id
WHERE e.salary > d.avg_sal;

-- Strategy: always lock rows in ascending ID order
-- Transaction A:
UPDATE accounts SET balance = balance - 100 WHERE id = 1;
UPDATE accounts SET balance = balance + 100 WHERE id = 2;

-- Transaction B (same order):
UPDATE accounts SET balance = balance + 50 WHERE id = 1;
UPDATE accounts SET balance = balance - 50 WHERE id = 2;

-- Range partitioning by date (PostgreSQL)
CREATE TABLE orders (
  id SERIAL,
  order_date DATE,
  amount DECIMAL(10,2)
) PARTITION BY RANGE (order_date);

CREATE TABLE orders_2024 PARTITION OF orders
  FOR VALUES FROM ('2024-01-01') TO ('2025-01-01');
CREATE TABLE orders_2025 PARTITION OF orders
  FOR VALUES FROM ('2025-01-01') TO ('2026-01-01');
